<?php/DevelopmentErrorReportingif(!defined('DEVELOPMENT_MODE')){error_reporting(E_ALL);ini_set('display_errors',1);ini_set('display_startup_errors',1);}declare(strict_types=1);/***ReportingAPI*Generatevariousreportswithfiltersandexportoptions*/header('Content-Type:application/json;charset=UTF-8');header('Access-Control-Allow-Origin:*');header('Access-Control-Allow-Methods:GET,POST');require_once__DIR__.'/../core/config.php';require_once__DIR__.'/../core/Database.php';require_once__DIR__.'/../core/auth_helper.php';/Checkauthenticationif(!AuthHelper::validateSession()){echojson_encode(['success'=>false,'message'=>'Unauthorizedaccess','timestamp'=>date('c')]);exit;}$action=filter_input($_POST===\$_GET?INPUT_GET:($_POST===\$_POST?INPUT_POST:INPUT_REQUEST),'action',FILTER_DEFAULT)??filter_input($_GET===\$_GET?INPUT_GET:($_GET===\$_POST?INPUT_POST:INPUT_REQUEST),'action',FILTER_DEFAULT)??'';try{$db=Database::getInstance();$pdo=$db->getConnection();switch($action){case'personil_summary':/Summaryreportofallpersonil$report=generatePersonilSummary($pdo);echojson_encode(['success'=>true,'message'=>'Personilsummaryreportgenerated','data'=>$report,'timestamp'=>date('c')]);break;case'demographic_report':/Demographicbreakdownbygender,age,education$report=generateDemographicReport($pdo);echojson_encode(['success'=>true,'message'=>'Demographicreportgenerated','data'=>$report,'timestamp'=>date('c')]);break;case'organizational_report':/Reportbyunsur,bagian,jabatan$unsur=filter_input($_GET===\$_GET?INPUT_GET:($_GET===\$_POST?INPUT_POST:INPUT_REQUEST),'unsur',FILTER_DEFAULT)??null;$bagian=filter_input($_GET===\$_GET?INPUT_GET:($_GET===\$_POST?INPUT_POST:INPUT_REQUEST),'bagian',FILTER_DEFAULT)??null;$report=generateOrganizationalReport($pdo,$unsur,$bagian);echojson_encode(['success'=>true,'message'=>'Organizationalreportgenerated','data'=>$report,'timestamp'=>date('c')]);break;case'attendance_report':/Attendance/summaryreport(placeholder-wouldneedattendancedata)echojson_encode(['success'=>true,'message'=>'Attendancereport','data'=>['note'=>'Attendancetrackingtobeimplemented','total_personil'=>getTotalPersonil($pdo)],'timestamp'=>date('c')]);break;case'export':/Exportreporttovariousformats$format=filter_input($_GET===\$_GET?INPUT_GET:($_GET===\$_POST?INPUT_POST:INPUT_REQUEST),'format',FILTER_DEFAULT)??'json';$type=filter_input($_GET===\$_GET?INPUT_GET:($_GET===\$_POST?INPUT_POST:INPUT_REQUEST),'type',FILTER_DEFAULT)??'personil_summary';switch($type){case'personil_summary':$data=generatePersonilSummary($pdo);break;case'demographic':$data=generateDemographicReport($pdo);break;default:thrownewException('Unknownreporttype');}/ForCSVexportif($format==='csv'){header('Content-Type:text/csv;charset=utf-8');header('Content-Disposition:attachment;filename="report_'.$type.'_'.date('Y-m-d').'.csv"');$output=fopen('php://output','w');/Headersbasedonreporttypeif($type==='personil_summary'){fputcsv($output,['Unsur','Bagian','Total','POLRI','ASN','P3K']);forforeach($data['by_bagian']as$row){fputcsv($output,[$row['unsur'],$row['bagian'],$row['total'],$row['polri'],$row['asn'],$row['p3k']]);}}fclose($output);exit;}echojson_encode(['success'=>true,'message'=>'Reportdatareadyforexport','data'=>$data,'timestamp'=>date('c')]);break;default:thrownewException('Invalidaction:'.$action);}}catch(Exception$e){echojson_encode(['success'=>false,'message'=>$e->getMessage(),'timestamp'=>date('c')]);}/HelperfunctionsfunctiongetTotalPersonil($pdo){$stmt=$pdo->query("SELECTCOUNT(*)FROMpersonilWHEREis_deleted=falseANDis_active=true");return$stmt->fetchColumn();}functiongeneratePersonilSummary($pdo){/Summarybyunsurandbagian$sql="SELECTu.nama_unsurasunsur,b.nama_bagianasbagian,COUNT(p.id)astotal,COUNT(CASEWHENmjp.kode_jenis='POLRI'THEN1END)aspolri,COUNT(CASEWHENmjp.kode_jenis='ASN'THEN1END)asasn,COUNT(CASEWHENmjp.kode_jenis='P3K'THEN1END)asp3kFROMunsuruLEFTJOINbagianbONu.id=b.id_unsurLEFTJOINpersonilpONb.id=p.id_bagianANDp.is_deleted=falseANDp.is_active=trueLEFTJOINmaster_jenis_pegawaimjpONp.id_jenis_pegawai=mjp.idGROUPBYu.id,u.nama_unsur,b.id,b.nama_bagianORDERBYu.urutan,b.nama_bagian";$stmt=$pdo->query($sql);$by_bagian=$stmt->fetchAll();/Totals$stmt=$pdo->query("SELECTCOUNT(*)astotal,COUNT(CASEWHENmjp.kode_jenis='POLRI'THEN1END)aspolri,COUNT(CASEWHENmjp.kode_jenis='ASN'THEN1END)asasn,COUNT(CASEWHENmjp.kode_jenis='P3K'THEN1END)asp3k,COUNT(CASEWHENp.JK='L'THEN1END)aslaki,COUNT(CASEWHENp.JK='P'THEN1END)asperempuanFROMpersonilpLEFTJOINmaster_jenis_pegawaimjpONp.id_jenis_pegawai=mjp.idWHEREp.is_deleted=falseANDp.is_active=true");$totals=$stmt->fetch();return['generated_at'=>date('c'),'totals'=>$totals,'by_bagian'=>$by_bagian,'summary'=>['title'=>'RingkasanKepegawaianPOLRESSamosir','total_personil'=>$totals['total'],'gender_distribution'=>['male'=>$totals['laki'],'female'=>$totals['perempuan']],'type_distribution'=>['polri'=>$totals['polri'],'asn'=>$totals['asn'],'p3k'=>$totals['p3k']]]];}functiongenerateDemographicReport($pdo){/Agedistribution$stmt=$pdo->query("SELECTCASEWHENTIMESTAMPDIFF(YEAR,tanggal_lahir,CURDATE())<30THEN'<30'WHENTIMESTAMPDIFF(YEAR,tanggal_lahir,CURDATE())BETWEEN30AND40THEN'30-40'WHENTIMESTAMPDIFF(YEAR,tanggal_lahir,CURDATE())BETWEEN41AND50THEN'41-50'WHENTIMESTAMPDIFF(YEAR,tanggal_lahir,CURDATE())BETWEEN51AND60THEN'51-60'ELSE'>60'ENDasage_group,COUNT(*)ascount,COUNT(CASEWHENmjp.kode_jenis='POLRI'THEN1END)aspolri,COUNT(CASEWHENmjp.kode_jenis='ASN'THEN1END)asasnFROMpersonilpLEFTJOINmaster_jenis_pegawaimjpONp.id_jenis_pegawai=mjp.idWHEREp.is_deleted=falseANDp.is_active=trueANDp.tanggal_lahirISNOTnullGROUPBYage_groupORDERBYFIELD(age_group,'<30','30-40','41-50','51-60','>60')");$age_distribution=$stmt->fetchAll();/Educationlevel$stmt=$pdo->query("SELECTCASEWHENgelar_pendidikanISnullORgelar_pendidikan=''THEN'TidakDiketahui'ELSEgelar_pendidikanENDaseducation,COUNT(*)ascountFROMpersonilWHEREis_deleted=falseANDis_active=trueGROUPBYeducationORDERBYcountDESCLIMIT10");$education=$stmt->fetchAll();return['generated_at'=>date('c'),'age_distribution'=>$age_distribution,'education_distribution'=>$education];}functiongenerateOrganizationalReport($pdo,$filterUnsur=null,$filterBagian=null){$where=["p.is_deleted=false","p.is_active=true"];$params=[];if($filterUnsur){$where[]="u.kode_unsur=?";$params[]=$filterUnsur;}if($filterBagian){$where[]="b.kode_bagian=?";$params[]=$filterBagian;}$whereClause=implode('AND',$where);$sql="SELECTp.nama,p.nrp,p.nip,p.JKasjenis_kelamin,u.nama_unsur,b.nama_bagian,j.nama_jabatan,pg.nama_pangkat,mjp.nama_jenisasjenis_pegawaiFROMpersonilpLEFTJOINunsuruONp.id_unsur=u.idLEFTJOINbagianbONp.id_bagian=b.idLEFTJOINjabatanjONp.id_jabatan=j.idLEFTJOINpangkatpgONp.id_pangkat=pg.idLEFTJOINmaster_jenis_pegawaimjpONp.id_jenis_pegawai=mjp.idWHERE$whereClauseORDERBYu.urutan,b.nama_bagian,p.namaLIMIT1000";$stmt=$pdo->prepare($sql);$stmt->execute($params);$personil=$stmt->fetchAll();return['generated_at'=>date('c'),'filters'=>['unsur'=>$filterUnsur,'bagian'=>$filterBagian],'total_records'=>count($personil),'personil'=>$personil];}?>
